def generate_plant_model(features, label):
    for feature in features:
        if "@startuml" not in feature or "@enduml" not in feature:
            raise ValueError("Invalid @startuml or @enduml tags found in each feature")
        node = {
            "@startuml": feature["@startuml"],
            "@enduml": feature["@enduml"]
        }
        label_node = label.split('@')
        node[feature['label']] = label

        return label_node
